public int maximumRemovals(String s, String p, int[] removable) {
    int low = 0, high = removable.length;
    while (low < high) {
        int mid = low + (high - low + 1) / 2;
        char[] ss = s.toCharArray();
        for (int i = 0; i < mid; ++i) {
            ss[removable[i]] = '-';
        }
        int j = 0, i = 0;
        while (i < ss.length && j < p.length()) {
            if (ss[i] == p.charAt(j)) {
                ++j;
            }
            ++i;
        }
        if (j == p.length()) {
            low = mid;
        } else {
            high = mid - 1;
        }
    }
    return low;
}
